<?php
namespace App\Http\Requests\Admin;
use App\Support\UniqueSlug; use Illuminate\Foundation\Http\FormRequest; use Illuminate\Validation\Rule;
class UpdateProjectRequest extends FormRequest { public function authorize(): bool { return true; } protected function prepareForValidation(): void { $id=$this->route('project')?->id; $this->merge(['slug'=>UniqueSlug::make('projects', $this->input('slug') ?: $this->input('title', 'project'), $id)]); } public function rules(): array { $id=$this->route('project')?->id; return ['project_category_id'=>['nullable','exists:project_categories,id'],'title'=>['required','string','max:180'],'slug'=>['nullable','string','max:200',Rule::unique('projects','slug')->ignore($id)],'featured_image'=>['nullable','image','mimes:jpg,jpeg,png,webp','max:4096'],'progress_percentage'=>['required','integer','min:0','max:100'],'short_description'=>['nullable','string','max:1000'],'full_description'=>['nullable','string'],'status'=>['nullable','boolean'],'is_featured'=>['nullable','boolean'],'sort_order'=>['nullable','integer','min:0'],'seo_title'=>['nullable','string','max:180'],'seo_description'=>['nullable','string','max:500']]; } }
